using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;/// <summary>/// Edge case: Try to get EHR record with empty/nil ID/// Expected: 400 Bad Request or routing error/// </summary>public class EhrServiceTests_GetEhrRecord_WithEmptyId_ShouldReturnBadRequest : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task GetEhrRecord_WithEmptyId_ShouldReturnBadRequest()    {        await AuthenticateAsDoctorAsync(EhrClient);        var emptyGuid = Guid.Empty;                var response = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.GetRecord(emptyGuid));        Assert.True(            response.StatusCode == HttpStatusCode.BadRequest ||             response.StatusCode == HttpStatusCode.NotFound,            $"Expected 400 or 404, got {response.StatusCode}");    }}